export interface QuizQuestion {
  questionText: string;
  options: string[];
  correctOptionIndex: number;
}

export enum GameState {
  START = 'START',
  LOADING = 'LOADING',
  PLAYING = 'PLAYING',
  FINISHED = 'FINISHED',
  ERROR = 'ERROR'
}

export interface QuizResult {
  score: number;
  totalQuestions: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { QuizQuestion } from "../types";

// Fallback questions in case API fails or key is missing
const FALLBACK_QUESTIONS: QuizQuestion[] = [
  {
    questionText: "Hva er hovedstaden i Norge?",
    options: ["Bergen", "Oslo", "Trondheim"],
    correctOptionIndex: 1
  },
  {
    questionText: "Hvilket år ble grunnloven på Eidsvoll underskrevet?",
    options: ["1814", "1905", "1945"],
    correctOptionIndex: 0
  },
  {
    questionText: "Hva er Norges lengste elv?",
    options: ["Numedalslågen", "Otra", "Glomma"],
    correctOptionIndex: 2
  }
];

export const fetchQuizQuestions = async (): Promise<QuizQuestion[]> => {
  try {
    const apiKey = process.env.API_KEY;

    if (!apiKey) {
      console.warn("API Key missing, using fallback questions.");
      return FALLBACK_QUESTIONS;
    }

    const ai = new GoogleGenAI({ apiKey });

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: "Lag 3 engasjerende allmennkunnskap-spørsmål på norsk. Hvert spørsmål må ha 3 korte svaralternativer, hvor kun ett er riktig. Ikke gjør spørsmålene for lange, da de skal vises på mobil.",
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              questionText: { type: Type.STRING },
              options: { 
                type: Type.ARRAY, 
                items: { type: Type.STRING } 
              },
              correctOptionIndex: { 
                type: Type.INTEGER, 
                description: "0 for the first option, 1 for the second, 2 for the third." 
              }
            },
            required: ["questionText", "options", "correctOptionIndex"]
          }
        }
      }
    });

    if (response.text) {
      const data = JSON.parse(response.text) as QuizQuestion[];
      // Validate data structure lightly
      if (Array.isArray(data) && data.length >= 3) {
        return data.slice(0, 3);
      }
    }

    return FALLBACK_QUESTIONS;

  } catch (error) {
    console.error("Failed to fetch from Gemini:", error);
    return FALLBACK_QUESTIONS;
  }
};

