import { QuestionCard } from './components/QuestionCard';
import { ResultView } from './components/ResultView';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.START);
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [score, setScore] = useState(0);

  // Load questions when entering Loading state
  useEffect(() => {
    if (gameState === GameState.LOADING) {
      const loadData = async () => {
        const fetchedQuestions = await fetchQuizQuestions();
        setQuestions(fetchedQuestions);
        // Use a small timeout to ensure loading animation is felt (smoother UX)
        setTimeout(() => {
          setGameState(GameState.PLAYING);
        }, 800);
      };
      loadData();
    }
  }, [gameState]);

  const handleStart = () => {
    setScore(0);
    setCurrentQuestionIndex(0);
    setGameState(GameState.LOADING);
  };

  const handleAnswer = (selectedIndex: number) => {
    const currentQ = questions[currentQuestionIndex];
    if (selectedIndex === currentQ.correctOptionIndex) {
      setScore((prev) => prev + 1);
    }

    if (currentQuestionIndex < questions.length - 1) {
      setCurrentQuestionIndex((prev) => prev + 1);
    } else {
      setGameState(GameState.FINISHED);
    }
  };

  return (
    <div className="h-[100dvh] w-full flex items-center justify-center bg-[#f5f3f1] overflow-hidden font-sans">
      <div className="w-full h-full max-w-lg bg-white sm:h-auto sm:min-h-[600px] sm:rounded-2xl sm:shadow-2xl overflow-hidden relative">

        {/* Loading Overlay */}
        {gameState === GameState.LOADING && (
          <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-white/95 backdrop-blur-sm">
            <div className="animate-spin rounded-full h-16 w-16 border-t-4 border-b-4 border-[#eb5c3b] mb-6"></div>
            <p className="text-[#261e19] font-bold text-xl animate-pulse">Laster quiz...</p>
          </div>
        )}

        {/* Views Switcher */}
        <main className="h-full w-full">
          {gameState === GameState.START && (
            <StartView onStart={handleStart} />
          )}

          {gameState === GameState.PLAYING && questions.length > 0 && (
            <QuestionCard
              question={questions[currentQuestionIndex]}
              questionNumber={currentQuestionIndex + 1}
              totalQuestions={questions.length}
              onAnswer={handleAnswer}
            />
          )}

          {gameState === GameState.FINISHED && (
            <ResultView 
              score={score} 
              totalQuestions={questions.length} 
              onRestart={handleStart} 
            />
          )}

          {gameState === GameState.PLAYING && questions.length === 0 && (
             <div className="flex flex-col items-center justify-center h-full p-4">
                <p>Noe gikk galt. Prøv igjen.</p>
                <button onClick={() => setGameState(GameState.START)} className="mt-4 text-[#eb5c3b] font-bold">Hjem</button>
             </div>
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

