export const fetchQuizQuestions = async (): Promise<QuizQuestion[]> => {
  // Simulerer en kort lasteperiode for UI-flyt
  await new Promise(resolve => setTimeout(resolve, 500));

  // Kopierer arrayet for ikke å endre originalen
  const shuffled = [...QUIZ_QUESTIONS];

  // Fisher-Yates shuffle algoritme for å stokke spørsmålene
  for (let i = shuffled.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
  }

  // Returnerer de 3 første spørsmålene etter stokking
  return shuffled.slice(0, 3);
};

