import React, { useEffect } from 'react';
import confetti from 'canvas-confetti';

interface ResultViewProps {
  score: number;
  totalQuestions: number;
  onRestart: () => void;
}

export const ResultView: React.FC<ResultViewProps> = ({ score, totalQuestions, onRestart }) => {
  const isWinner = score === totalQuestions;
  const mistakes = totalQuestions - score;

  useEffect(() => {
    if (isWinner) {
      // Kjør konfetti i 3 sekunder
      const duration = 3000;
      const end = Date.now() + duration;

      const frame = () => {
        // Skyt konfetti fra venstre kant
        confetti({
          particleCount: 5,
          angle: 60,
          spread: 55,
          origin: { x: 0 },
          colors: ['#eb5c3b', '#ffffff'] // Oransje og Hvit
        });
        // Skyt konfetti fra høyre kant
        confetti({
          particleCount: 5,
          angle: 120,
          spread: 55,
          origin: { x: 1 },
          colors: ['#eb5c3b', '#ffffff']
        });

        if (Date.now() < end) {
          requestAnimationFrame(frame);
        }
      };

      frame();
    }
  }, [isWinner]);

  if (isWinner) {
    return (
      <div className="flex flex-col items-center justify-center min-h-full p-6 text-center animate-pop-in bg-black">
        <div className="mb-6 md:mb-8 p-6 bg-[#eb5c3b] rounded-full shadow-[0_0_30px_rgba(235,92,59,0.5)]">
