        <p className="text-lg md:text-2xl text-gray-300 mb-8 md:mb-12 font-medium leading-relaxed">
          Du svarte alt riktig! Vis denne skjermen for å få premien din.
        </p>

        <div className="bg-[#1a1a1a] border-4 border-dashed border-[#eb5c3b] p-8 md:p-10 rounded-xl w-full max-w-sm mb-8 shadow-lg">
          <p className="font-mono text-[#eb5c3b] font-black text-4xl md:text-5xl tracking-widest break-all drop-shadow-md">VINNER</p>
