import React, { useEffect } from 'react';
import confetti from 'canvas-confetti';

interface ResultViewProps {
  score: number;
  totalQuestions: number;
  onRestart: () => void;
}

export const ResultView: React.FC<ResultViewProps> = ({ score, totalQuestions, onRestart }) => {
  const isWinner = score === totalQuestions;
  const mistakes = totalQuestions - score;

  useEffect(() => {
    if (isWinner) {
      // Fyrverkeri-effekt for vinner
      const duration = 5000;
      const animationEnd = Date.now() + duration;
      const defaults = { startVelocity: 30, spread: 360, ticks: 60, zIndex: 0 };

      const randomInRange = (min: number, max: number) => {
        return Math.random() * (max - min) + min;
      }

      const interval: any = setInterval(function() {
        const timeLeft = animationEnd - Date.now();

        if (timeLeft <= 0) {
          return clearInterval(interval);
        }

        const particleCount = 50 * (timeLeft / duration);

        confetti({
          ...defaults, 
          particleCount,
          origin: { x: randomInRange(0.1, 0.3), y: Math.random() - 0.2 }
        });
        confetti({
          ...defaults, 
          particleCount,
          origin: { x: randomInRange(0.7, 0.9), y: Math.random() - 0.2 }
        });
      }, 250);

      return () => clearInterval(interval);
    } else {
      // "Trist regn" / Aske effekt for taper
      const duration = 5000;
      const end = Date.now() + duration;

      const frame = () => {
        confetti({
          particleCount: 2,
          angle: 270, // Rett ned
          spread: 0,
          origin: { x: Math.random(), y: -0.1 }, // Starter over skjermen
          colors: ['#ffffff', '#a8a8a8', '#555555'], // Gråtoner
          gravity: 1.5,
          scalar: 0.8,
          drift: 0,
          ticks: 300
        });

        if (Date.now() < end) {
          requestAnimationFrame(frame);
        }
      };
      frame();
    }
  }, [isWinner]);

