import React, { useState } from 'react';
import { QuizQuestion } from '../types';

interface QuestionCardProps {
  question: QuizQuestion;
  questionNumber: number;
  totalQuestions: number;
  onAnswer: (selectedIndex: number) => void;
}

export const QuestionCard: React.FC<QuestionCardProps> = ({
  question,
  questionNumber,
  totalQuestions,
  onAnswer,
}) => {
  const [selectedOption, setSelectedOption] = useState<number | null>(null);

  const handleOptionClick = (index: number) => {
    // Hindrer dobbeltklikk
    if (selectedOption !== null) return;

    // Haptic feedback for mobile
    if (typeof navigator !== 'undefined' && navigator.vibrate) {
      navigator.vibrate(50);
    }

    setSelectedOption(index);

    // Vent litt før vi går videre for å vise animasjonen
    setTimeout(() => {
      onAnswer(index);
    }, 350);
  };

  return (
    <div className="flex flex-col min-h-full w-full max-w-md mx-auto p-4 md:p-6 animate-slide-up">
      {/* Header / Progress */}
      <div className="flex flex-col mb-6 w-full">
        <div className="flex justify-between items-end mb-2">
           <span className="text-sm md:text-base font-bold text-[#eb5c3b] tracking-wider uppercase">
            Spørsmål {questionNumber}/{totalQuestions}
          </span>
        </div>
        <div className="h-2 md:h-3 w-full bg-gray-200 rounded-full overflow-hidden">
          <div 
            className="h-full bg-[#eb5c3b] transition-all duration-500 ease-out shadow-[0_0_10px_#eb5c3b]"
            style={{ width: `${(questionNumber / totalQuestions) * 100}%` }}
          />
        </div>
      </div>

      {/* Question */}
      <div className="flex-grow flex flex-col justify-center py-2">
        <h2 className="text-3xl md:text-4xl font-bold text-gray-900 mb-6 md:mb-10 leading-snug text-center">
          {question.questionText}
        </h2>

        {/* Options */}
        <div className="space-y-3 md:space-y-4 w-full">
          {question.options.map((option, index) => {
            const isSelected = selectedOption === index;
            const isAnySelected = selectedOption !== null;

            return (
              <button
                key={index}
                onClick={() => handleOptionClick(index)}
                disabled={isAnySelected}
                className={`
                  w-full text-center font-semibold py-4 px-5 md:py-5 md:px-6 rounded-lg shadow-md 
                  text-lg md:text-xl touch-manipulation focus:outline-none 
                  border-2 transition-all duration-200 transform
                  ${isSelected 
                    ? 'bg-[#c24025] border-[#c24025] text-white scale-[0.98]' 
                    : 'bg-[#eb5c3b] border-[#eb5c3b] text-white'
                  }
                  ${!isAnySelected ? 'hover:bg-[#d94e30] hover:border-[#d94e30] active:bg-[#c24025] active:border-[#c24025]' : ''}
                  ${isAnySelected && !isSelected ? 'opacity-40 cursor-not-allowed' : ''}
                `}
              >
                {option}
              </button>
            );
          })}
        </div>
      </div>
    </div>
  );
};

